43	// refreshGroup serializes concurrent RefreshQuota / RefreshAccount calls
44	// across all *Runner instances. Per CONTRACT-004 invariant #6 Runners are
45	// stateless wrappers — sharing the singleflight group at package scope
46	// keeps single-flight semantics correct when callers construct fresh
47	// runner instances per call.
48	var refreshGroup singleflight.Group
49	
50	// QuotaStatus implements harnesses.QuotaHarness. It reads the cached
51	// snapshot owned by this harness and projects it onto QuotaStatus. A
52	// missing or undecodable cache is reported as State=QuotaUnavailable on
53	// a valid QuotaStatus value (no error) per CONTRACT-004 §"Errors are
54	// reserved for call failure."
55	func (r *Runner) QuotaStatus(ctx context.Context, now time.Time) (harnesses.QuotaStatus, error) {
56		if err := ctx.Err(); err != nil {
57			return harnesses.QuotaStatus{}, err
58		}
59		snap, ok := ReadGeminiQuota()
60		if !ok || snap == nil {
61			return harnesses.QuotaStatus{
62				Source:            "cache",
63				State:             harnesses.QuotaUnavailable,
64				RoutingPreference: harnesses.RoutingPreferenceUnknown,
65				Reason:            "no cached snapshot",
66			}, nil
67		}
68		return geminiQuotaStatusFromSnapshot(snap, now), nil
69	}
70	
71	// RefreshQuota implements harnesses.QuotaHarness. It probes the gemini
72	// CLI via PTY unconditionally and persists the result through the
73	// harness's owned cache. Single-flight per package: concurrent callers
74	// share one cohort and observe the just-written cached state. Probe
75	// failure (binary missing, PTY error, parse failure) is reported as
76	// State=QuotaUnavailable on a valid QuotaStatus value, not as an error.
77	func (r *Runner) RefreshQuota(ctx context.Context) (harnesses.QuotaStatus, error) {
78		if err := ctx.Err(); err != nil {
79			return harnesses.QuotaStatus{}, err
80		}
81		v, err, _ := refreshGroup.Do("gemini:refresh-quota", func() (any, error) {
82			return r.refreshQuotaLocked(ctx), nil
83		})
84		if err != nil {
85			return harnesses.QuotaStatus{}, err
86		}
87		return v.(harnesses.QuotaStatus), nil
88	}
89	
90	// refreshQuotaLocked is the single-flight critical section. It probes
91	// PTY, writes the cache on success, and returns the projected status.
92	// Probe failure is folded into State=QuotaUnavailable.
93	func (r *Runner) refreshQuotaLocked(ctx context.Context) harnesses.QuotaStatus {
94		now := time.Now()
95		timeout := geminiQuotaFreshness
96		if deadline, ok := ctx.Deadline(); ok {
97			remaining := time.Until(deadline)
98			if remaining > 0 && remaining < timeout {
99				timeout = remaining
100			}
101		}
102		var opts []QuotaPTYOption
103		if r.Binary != "" {
104			opts = append(opts, WithQuotaPTYCommand(r.Binary))
105		}
106		windows, _, err := captureGeminiQuotaViaPTY(ctx, timeout, opts...)
107		if err != nil {
108			state := harnesses.QuotaUnavailable
109			reason := err.Error()
110			lower := strings.ToLower(reason)
111			switch {
112			case strings.Contains(lower, "not found") || strings.Contains(lower, "executable file not found"):
113				state = harnesses.QuotaUnavailable
114			case strings.Contains(lower, "unauth") || strings.Contains(lower, "credential"):
115				state = harnesses.QuotaUnauthenticated
116			}
117			return harnesses.QuotaStatus{
118				Source:            "pty",
119				CapturedAt:        now.UTC(),
120				State:             state,
121				RoutingPreference: harnesses.RoutingPreferenceUnknown,
122				Reason:            reason,
123			}
124		}
125		account := ReadAuthEvidence(now).Account
126		snap := GeminiQuotaSnapshot{
127			CapturedAt: now.UTC(),
128			Windows:    windows,
129			Source:     "pty",
130			Account:    account,
131		}
132		if path, pathErr := GeminiQuotaCachePath(); pathErr == nil {
133			_ = WriteGeminiQuota(path, snap)
134		}
135		return geminiQuotaStatusFromSnapshot(&snap, now)
136	}
