188	// ResolveModelAlias implements harnesses.ModelDiscoveryHarness. Returns
189	// harnesses.ErrAliasNotResolvable when the supplied family is not a
190	// recognized gemini alias or when the discovery snapshot has no concrete
191	// model matching the family.
192	func (r *Runner) ResolveModelAlias(family string, snapshot harnesses.ModelDiscoverySnapshot) (string, error) {
193		normalized := strings.ToLower(strings.TrimSpace(family))
194		if !isSupportedGeminiAlias(normalized) {
195			return "", harnesses.ErrAliasNotResolvable
196		}
197		resolved := ResolveGeminiModelAlias(normalized, snapshot)
198		if resolved == "" || resolved == normalized {
199			// ResolveGeminiModelAlias returns the input unchanged when no
200			// concrete model matches. Treat that as not-resolvable so the
201			// CONTRACT-004 negative-path semantics are preserved.
202			return "", harnesses.ErrAliasNotResolvable
203		}
204		return resolved, nil
205	}
