1	package gemini
2	
3	import (
4		"fmt"
5		"regexp"
6		"strings"
7		"time"
8	
9		"github.com/easel/fizeau/internal/harnesses"
10	)
11	
12	const GeminiModelDiscoveryFreshnessWindow = 24 * time.Hour
13	
14	var (
15		geminiANSISequencePattern = regexp.MustCompile(`\x1b\[[0-9;?]*[ -/]*[@-~]`)
16		geminiModelPattern        = regexp.MustCompile(`\bgemini-[A-Za-z0-9][A-Za-z0-9._-]*\b`)
17		geminiMajorPattern        = regexp.MustCompile(`^gemini-[0-9]+(?:[.-][0-9]+)?$`)
18	)
19	
20	func DefaultGeminiModelDiscovery() harnesses.ModelDiscoverySnapshot {
21		return harnesses.ModelDiscoverySnapshot{
22			CapturedAt:      time.Now().UTC(),
23			Models:          []string{"gemini", "gemini-2.5", "gemini-2.5-pro", "gemini-2.5-flash", "gemini-2.5-flash-lite"},
24			ReasoningLevels: nil,
25			Source:          "bundled:gemini-cli",
26			FreshnessWindow: GeminiModelDiscoveryFreshnessWindow.String(),
27			Detail:          "Gemini CLI model IDs are extracted from supplied CLI/API or bundled model-surface output; the harness exposes no stable per-request reasoning control",
28		}
29	}
30	
31	// ModelDiscoveryFromText extracts Gemini model IDs from caller-provided CLI
32	// output without assuming a current default model list.
33	func ModelDiscoveryFromText(text, source string) harnesses.ModelDiscoverySnapshot {
34		snapshot := DefaultGeminiModelDiscovery()
35		if source == "" {
36			source = "cli-output:gemini"
37		}
38		snapshot.Source = source
39		if models := parseGeminiModels(text); len(models) > 0 {
40			snapshot.Models = models
41		}
42		return snapshot
43	}
44	
45	func parseGeminiModels(text string) []string {
46		text = geminiANSISequencePattern.ReplaceAllString(strings.ReplaceAll(text, "\r\n", "\n"), "")
47		return uniqueGeminiStrings(geminiModelPattern.FindAllString(text, -1))
48	}
49	
50	func uniqueGeminiStrings(values []string) []string {
51		seen := map[string]bool{}
52		out := make([]string, 0, len(values))
53		for _, value := range values {
54			value = strings.TrimSpace(value)
55			if value == "" || value == "gemini-cli" || seen[value] {
56				continue
57			}
58			seen[value] = true
59			out = append(out, value)
60		}
61		return out
62	}
63	
64	func ResolveGeminiModelAlias(model string, snapshot harnesses.ModelDiscoverySnapshot) string {
65		model = strings.ToLower(strings.TrimSpace(model))
66		if model == "" {
67			return model
68		}
69		if model == "gemini" {
70			if resolved := latestGeminiModel("", snapshot.Models); resolved != "" {
71				return resolved
72			}
73			return model
74		}
75		if geminiMajorPattern.MatchString(model) {
76			prefix := strings.TrimPrefix(model, "gemini-")
77			if resolved := latestGeminiModel(prefix, snapshot.Models); resolved != "" {
78				return resolved
79			}
80		}
81		return model
82	}
83	
84	func latestGeminiModel(prefix string, models []string) string {
85		best := ""
86		var bestParts []int
87		bestRank := -1
88		for _, model := range models {
89			candidate := strings.ToLower(strings.TrimSpace(model))
90			parts, variant, ok := parseGeminiVersion(candidate)
91			if !ok {
92				continue
93			}
94			if prefix != "" && !strings.HasPrefix(versionKey(parts), strings.ReplaceAll(prefix, "-", ".")) {
95				continue
96			}
97			rank := geminiVariantRank(variant)
98			if best == "" || compareGeminiVersion(parts, rank, bestParts, bestRank) > 0 {
99				best = candidate
100				bestParts = parts
101				bestRank = rank
102			}
103		}
104		return best
105	}
106	
107	func parseGeminiVersion(model string) ([]int, string, bool) {
108		if !strings.HasPrefix(model, "gemini-") {
109			return nil, "", false
110		}
111		rest := strings.TrimPrefix(model, "gemini-")
112		raw := strings.FieldsFunc(rest, func(r rune) bool { return r == '.' || r == '-' })
113		if len(raw) == 0 {
114			return nil, "", false
115		}
116		parts := make([]int, 0, len(raw))
117		var variant []string
118		for _, part := range raw {
119			if part == "" {
120				return nil, "", false
121			}
122			n := 0
123			numeric := true
124			for _, r := range part {
125				if r < '0' || r > '9' {
126					numeric = false
127					break
128				}
129				n = n*10 + int(r-'0')
130			}
131			if numeric && len(variant) == 0 {
132				parts = append(parts, n)
133				continue
134			}
135			variant = append(variant, part)
136		}
137		if len(parts) == 0 {
138			return nil, "", false
139		}
140		return parts, strings.Join(variant, "-"), true
141	}
142	
143	func versionKey(parts []int) string {
144		out := make([]string, len(parts))
145		for i, part := range parts {
146			out[i] = fmt.Sprint(part)
147		}
148		return strings.Join(out, ".")
149	}
150	
151	func geminiVariantRank(variant string) int {
152		switch {
153		case strings.Contains(variant, "pro"):
154			return 30
155		case strings.Contains(variant, "flash") && !strings.Contains(variant, "lite"):
156			return 20
157		case strings.Contains(variant, "flash-lite"), strings.Contains(variant, "lite"):
158			return 10
159		case variant == "":
160			return 0
161		default:
162			return 5
163		}
164	}
165	
166	func compareGeminiVersion(a []int, aRank int, b []int, bRank int) int {
167		n := len(a)
168		if len(b) > n {
169			n = len(b)
170		}
171		for i := 0; i < n; i++ {
172			av, bv := 0, 0
173			if i < len(a) {
174				av = a[i]
175			}
176			if i < len(b) {
177				bv = b[i]
178			}
179			if av > bv {
180				return 1
181			}
182			if av < bv {
183				return -1
184			}
185		}
186		switch {
187		case aRank > bRank:
188			return 1
189		case aRank < bRank:
190			return -1
191		default:
192			return 0
193		}
194	}
