221	// geminiQuotaStatusFromSnapshot projects the per-harness snapshot onto
222	// harnesses.QuotaStatus, deriving State and RoutingPreference via the
223	// existing DecideGeminiQuotaRouting helper. Tier facts (Flash / Flash
224	// Lite / Pro) live in Windows with their distinguishing LimitID; no tier
225	// names appear in Detail.
226	func geminiQuotaStatusFromSnapshot(snap *GeminiQuotaSnapshot, now time.Time) harnesses.QuotaStatus {
227		decision := DecideGeminiQuotaRouting(snap, now, geminiQuotaFreshness)
228		pref, state := mapGeminiRoutingPreference(decision)
229		status := harnesses.QuotaStatus{
230			Source:            snap.Source,
231			CapturedAt:        snap.CapturedAt,
232			Fresh:             decision.Fresh,
233			Age:               decision.Age,
234			State:             state,
235			Windows:           append([]harnesses.QuotaWindow(nil), snap.Windows...),
236			RoutingPreference: pref,
237			Reason:            decision.Reason,
238		}
239		if snap.Account != nil {
240			acct := harnesses.AccountSnapshot{
241				Source:     "cache",
242				CapturedAt: snap.CapturedAt,
243				Fresh:      IsGeminiQuotaFresh(snap, now, geminiAccountFreshness),
244				PlanType:   snap.Account.PlanType,
245				Email:      snap.Account.Email,
246				OrgName:    snap.Account.OrgName,
247			}
248			if snap.Account.PlanType != "" || snap.Account.Email != "" {
249				acct.Authenticated = true
250			}
251			status.Account = &acct
252		}
253		return status
254	}
255	
256	// mapGeminiRoutingPreference translates today's PreferGemini+freshness
257	// decision into the CONTRACT-004 (RoutingPreference, QuotaStateValue)
258	// pair. Legacy semantics: missing snapshot ⇒ Unavailable/Unknown;
259	// stale ⇒ Stale/Blocked ("assume limited"); fresh+PreferGemini ⇒
260	// OK/Available; fresh+!PreferGemini ⇒ Blocked/Blocked.
261	func mapGeminiRoutingPreference(d GeminiQuotaRoutingDecision) (harnesses.RoutingPreference, harnesses.QuotaStateValue) {
262		if !d.SnapshotPresent {
263			return harnesses.RoutingPreferenceUnknown, harnesses.QuotaUnavailable
264		}
265		if !d.Fresh {
266			return harnesses.RoutingPreferenceBlocked, harnesses.QuotaStale
267		}
268		if d.PreferGemini {
269			return harnesses.RoutingPreferenceAvailable, harnesses.QuotaOK
270		}
271		return harnesses.RoutingPreferenceBlocked, harnesses.QuotaBlocked
272	}
273	
274	// geminiAccountSnapshotFromAuth projects an AuthSnapshot onto the
275	// universal AccountSnapshot type. Authenticated is true iff the
276	// underlying auth evidence reports an authenticated session;
277	// Unauthenticated is the explicit negative signal so the projection
278	// distinguishes "no evidence" from "evidence says signed out".
279	func geminiAccountSnapshotFromAuth(auth AuthSnapshot) harnesses.AccountSnapshot {
280		out := harnesses.AccountSnapshot{
281			Source:     auth.Source,
282			CapturedAt: auth.CapturedAt,
283			Fresh:      auth.Fresh,
284			Detail:     auth.Detail,
285		}
286		if auth.Account != nil {
287			out.PlanType = auth.Account.PlanType
288			out.Email = auth.Account.Email
289			out.OrgName = auth.Account.OrgName
290		}
291		if auth.Authenticated {
292			out.Authenticated = true
293		} else {
294			out.Unauthenticated = true
295		}
296		return out
297	}
