17	const (
18		// RuntimeTTL is the default cache TTL for runtime signals (ADR-012 §2).
19		RuntimeTTL = 5 * time.Minute
20		// RuntimeRefreshDeadline bounds how long a runtime signal refresh may take.
21		RuntimeRefreshDeadline = 5 * time.Second
22	
23		defaultWindowSize = 100
24		aliveCheckTimeout = 3 * time.Second
