27	// Store is the per-process in-memory state for runtime signal collection.
28	// It holds per-provider latency windows and the most recently observed
29	// rate-limit header signals. All methods are safe for concurrent use.
30	type Store struct {
31		mu        sync.RWMutex
32		latencies map[string]*LatencyWindow
33		headers   *headerStore
34	}
35	
36	// CollectInput describes the provider identity needed to assemble a runtime
37	// signal. Type controls the collection path; BaseURL is used by local
38	// providers for the live /v1/models check.
39	type CollectInput struct {
40		Type    string
41		BaseURL string
42	}
43	
44	// NewStore creates an empty Store ready for use.
45	func NewStore() *Store {
46		return &Store{
47			latencies: make(map[string]*LatencyWindow),
48			headers:   newHeaderStore(),
49		}
50	}
51	
52	// DefaultStore is the process-singleton Store used by the package-level
53	// RecordResponse and Collect functions.
54	var DefaultStore = NewStore()
55	
56	// RecordResponse records an HTTP response observation for a provider using the
57	// DefaultStore. providerType controls which header parser is applied
58	// ("openrouter", "anthropic", or any other value for the OpenAI parser).
59	func RecordResponse(provider string, h http.Header, latency time.Duration, providerType string) {
60		DefaultStore.RecordResponse(provider, h, latency, providerType)
61	}
62	
63	// RecordResponse records an HTTP response observation. It updates both the
64	// latency window and the header signal store for the named provider.
65	func (s *Store) RecordResponse(provider string, h http.Header, latency time.Duration, providerType string) {
66		win := s.latencyWindow(provider)
67		win.Record(latency)
68	
69		if h != nil {
70			now := time.Now()
71			var sig quotaheaders.Signal
72			switch providerType {
73			case "openrouter":
74				sig = quotaheaders.ParseOpenRouter(h, now)
75			case "anthropic":
76				sig = quotaheaders.ParseAnthropic(h, now)
77			default:
78				sig = quotaheaders.ParseOpenAI(h, now)
79			}
80			s.headers.record(provider, sig)
81		}
82	}
83	
84	// Collect assembles a runtime Signal for the named provider using
85	// DefaultStore.
86	func Collect(ctx context.Context, providerName string, cfg CollectInput) (Signal, error) {
87		return DefaultStore.Collect(ctx, providerName, cfg)
88	}
89	
90	// Collect assembles a runtime Signal for providerName. The cfg.Type field
91	// controls which collection path is used:
92	//
93	//   - "claude"       → existing internal/harnesses/claude/quota_cache.go
94	//   - "codex"        → existing internal/harnesses/codex/quota_cache.go
95	//   - "gemini"       → existing internal/harnesses/gemini/quota_cache.go
96	//   - "openrouter"   → most recently recorded rate-limit headers (OpenRouter parser)
97	//   - "openai", "anthropic", and unknown HTTP types → rate-limit headers
98	//   - local types    → HTTP GET /v1/models alive check (no quota concept)
99	func (s *Store) Collect(ctx context.Context, providerName string, cfg CollectInput) (Signal, error) {
100		sig := Signal{
101			Provider:   providerName,
102			Status:     StatusUnknown,
103			RecordedAt: time.Now().UTC(),
104		}
105	
106		s.mu.RLock()
107		win := s.latencies[providerName]
108		s.mu.RUnlock()
109		if win != nil {
110			sig.RecentP50Latency = win.P50()
111		}
112	
113		providerType := cfg.Type
114	
115		switch providerType {
116		case "claude":
117			collectClaudeSignal(&sig)
118		case "codex":
119			collectCodexSignal(&sig)
120		case "gemini":
121			collectGeminiSignal(&sig)
122		case "ds4", "llama-server", "omlx", "lmstudio", "lucebox", "vllm", "rapid-mlx", "ollama":
123			collectLocalSignal(ctx, cfg.BaseURL, &sig)
124		default:
125			s.collectHeaderSignal(providerName, &sig)
126		}
127	
128		return sig, nil
129	}
