131	// CacheSource returns the discoverycache.Source descriptor for a provider's
132	// runtime signal. The file path resolves to runtime/<provider>.json.
133	func CacheSource(providerName string) discoverycache.Source {
134		return discoverycache.Source{
135			Tier:            "runtime",
136			Name:            providerName,
137			TTL:             RuntimeTTL,
138			RefreshDeadline: RuntimeRefreshDeadline,
139		}
140	}
141	
142	// Write serializes sig and stores it in M1's runtime cache tier. The cache
143	// file lands at <cache.Root>/runtime/<sig.Provider>.json.
144	func Write(cache *discoverycache.Cache, sig Signal) error {
145		data, err := json.Marshal(sig)
146		if err != nil {
147			return err
148		}
149		src := CacheSource(sig.Provider)
150		return cache.Refresh(src, func(_ context.Context) ([]byte, error) {
151			return data, nil
152		})
153	}
154	
155	// ReadCached reads a Signal from M1's runtime cache for providerName.
156	// Returns (nil, false) when the entry is absent or cannot be decoded.
157	func ReadCached(cache *discoverycache.Cache, providerName string) (*Signal, bool) {
158		src := CacheSource(providerName)
159		result, err := cache.Read(src)
160		if err != nil || result.Data == nil {
161			return nil, false
162		}
163		var sig Signal
164		if err := json.Unmarshal(result.Data, &sig); err != nil {
165			return nil, false
166		}
167		return &sig, true
168	}
