172	func collectClaudeSignal(sig *Signal) {
173		snap, ok := claudecache.ReadClaudeQuota()
174		if !ok || snap == nil {
175			return // StatusUnknown
176		}
177		if claudecache.ClaudeQuotaSnapshotAge(snap, time.Now()) > claudecache.DefaultClaudeQuotaStaleAfter {
178			return // StatusUnknown; snapshot is stale
179		}
180		if snap.WeeklyRemaining <= 0 || snap.FiveHourRemaining <= 0 {
181			sig.Status = StatusExhausted
182			zero := 0
183			sig.QuotaRemaining = &zero
184			return
185		}
186		sig.Status = StatusAvailable
187		rem := snap.FiveHourRemaining
188		sig.QuotaRemaining = &rem
189	}
