210	func collectGeminiSignal(sig *Signal) {
211		snap, ok := geminicache.ReadGeminiQuota()
212		if !ok || snap == nil {
213			return // StatusUnknown
214		}
215		if geminicache.GeminiQuotaSnapshotAge(snap, time.Now()) > geminicache.DefaultGeminiQuotaStaleAfter {
216			return // StatusUnknown; snapshot is stale
217		}
218		decision := geminicache.DecideGeminiQuotaRouting(snap, time.Now(), 0)
219		if decision.PreferGemini {
220			sig.Status = StatusAvailable
221		} else {
222			sig.Status = StatusExhausted
223			zero := 0
224			sig.QuotaRemaining = &zero
225		}
226	}
