228	// collectHeaderSignal reads the most recently recorded rate-limit header signal
229	// for the provider and populates sig accordingly.
230	func (s *Store) collectHeaderSignal(providerName string, sig *Signal) {
231		hSig, ok := s.headers.get(providerName)
232		if !ok {
233			return // StatusUnknown; no headers observed yet
234		}
235		exhausted, retryAfter := hSig.IsExhausted(time.Now())
236		if exhausted {
237			sig.Status = StatusExhausted
238			zero := 0
239			sig.QuotaRemaining = &zero
240			if !retryAfter.IsZero() {
241				t := retryAfter
242				sig.QuotaResetAt = &t
243			}
244			return
245		}
246		sig.Status = StatusAvailable
247		switch {
248		case hSig.RemainingRequests >= 0:
249			rem := int(hSig.RemainingRequests)
250			sig.QuotaRemaining = &rem
251		case hSig.RemainingTokens >= 0:
252			rem := int(hSig.RemainingTokens)
253			sig.QuotaRemaining = &rem
254		}
255		if !hSig.ResetTime.IsZero() {
256			t := hSig.ResetTime
257			sig.QuotaResetAt = &t
258		}
259	}
260	
261	// collectLocalSignal performs an HTTP GET /v1/models alive check for local
262	// providers. Local providers have no quota concept; only StatusAvailable vs
263	// StatusDegraded is determined.
264	func collectLocalSignal(ctx context.Context, baseURL string, sig *Signal) {
265		if baseURL == "" {
266			return // StatusUnknown
267		}
268		timeoutCtx, cancel := context.WithTimeout(ctx, aliveCheckTimeout)
269		defer cancel()
270	
271		checkURL := baseURL + "/v1/models"
272		req, err := http.NewRequestWithContext(timeoutCtx, http.MethodGet, checkURL, nil) // #nosec G107
273		if err != nil {
274			return // StatusUnknown; bad URL
275		}
276		resp, err := (&http.Client{}).Do(req)
277		if err != nil {
278			sig.Status = StatusDegraded
279			sig.LastErrorMsg = err.Error()
280			now := time.Now().UTC()
281			sig.LastErrorAt = &now
282			return
283		}
284		defer resp.Body.Close()
285	
286		if resp.StatusCode >= 200 && resp.StatusCode < 300 {
287			sig.Status = StatusAvailable
288			now := time.Now().UTC()
289			sig.LastSuccessAt = &now
290		} else {
291			sig.Status = StatusDegraded
292		}
293	}
294	
295	// ---- internal helpers -------------------------------------------------------
296	
297	func (s *Store) latencyWindow(provider string) *LatencyWindow {
298		s.mu.RLock()
299		win, ok := s.latencies[provider]
300		s.mu.RUnlock()
301		if ok {
302			return win
303		}
304		s.mu.Lock()
305		defer s.mu.Unlock()
306		if win, ok = s.latencies[provider]; ok {
307			return win
308		}
309		win = NewLatencyWindow(defaultWindowSize)
310		s.latencies[provider] = win
311		return win
312	}
