package gemini

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/productinfo"
	"github.com/easel/fizeau/internal/safefs"
)

// geminiQuotaSnapshot captures parsed Gemini CLI /model manage quota evidence
// in a durable cache so foreground routing consumers do not invoke PTY
// capture inline.
//
// Auth/account freshness on its own is NOT quota evidence. Only a parsed
// geminiQuotaSnapshot with one or more tier windows promotes Gemini beyond
// the "quota unknown" state.
type geminiQuotaSnapshot struct {
	CapturedAt time.Time               `json:"captured_at"`
	Windows    []harnesses.QuotaWindow `json:"windows"`
	Source     string                  `json:"source"` // e.g. "pty", "cassette"
	Account    *harnesses.AccountInfo  `json:"account,omitempty"`
	Detail     string                  `json:"detail,omitempty"`
}

const defaultGeminiQuotaStaleAfter = 15 * time.Minute

const geminiQuotaCacheEnv = "FIZEAU_GEMINI_QUOTA_CACHE"

func geminiQuotaCachePath() (string, error) {
	if path := os.Getenv(geminiQuotaCacheEnv); path != "" {
		return path, nil
	}
	if xdg := os.Getenv("XDG_STATE_HOME"); xdg != "" {
		return filepath.Join(xdg, productinfo.ConfigDir, "gemini-quota.json"), nil
	}
	home, err := os.UserHomeDir()
	if err != nil {
		return "", err
	}
	return filepath.Join(home, ".local", "state", productinfo.ConfigDir, "gemini-quota.json"), nil
}

func writeGeminiQuota(path string, snapshot geminiQuotaSnapshot) error {
	if path == "" {
		return fmt.Errorf("gemini quota cache path is empty")
	}
	if snapshot.CapturedAt.IsZero() {
		snapshot.CapturedAt = time.Now().UTC()
	} else {
		snapshot.CapturedAt = snapshot.CapturedAt.UTC()
	}
	if snapshot.Source == "" {
		snapshot.Source = "pty"
	}
	if err := os.MkdirAll(filepath.Dir(path), 0o750); err != nil {
		return fmt.Errorf("create gemini quota cache dir: %w", err)
	}
	data, err := json.MarshalIndent(snapshot, "", "  ")
	if err != nil {
		return fmt.Errorf("marshal gemini quota snapshot: %w", err)
	}
	data = append(data, '\n')
	tmpPath := path + ".tmp"
	if err := os.WriteFile(tmpPath, data, 0o600); err != nil {
		return fmt.Errorf("write gemini quota cache tmp: %w", err)
	}
	if err := os.Rename(tmpPath, path); err != nil {
		_ = os.Remove(tmpPath)
		return fmt.Errorf("rename gemini quota cache: %w", err)
	}
	if err := os.Chmod(path, 0o600); err != nil {
		return fmt.Errorf("chmod gemini quota cache: %w", err)
	}
	return nil
}

func readGeminiQuotaFrom(path string) (*geminiQuotaSnapshot, bool) {
	data, err := safefs.ReadFile(path)
	if err != nil {
		return nil, false
	}
	var snap geminiQuotaSnapshot
	if err := json.Unmarshal(data, &snap); err != nil {
		return nil, false
	}
	return &snap, true
}

func readGeminiQuota() (*geminiQuotaSnapshot, bool) {
	path, err := geminiQuotaCachePath()
	if err != nil {
		return nil, false
	}
	return readGeminiQuotaFrom(path)
}

func geminiQuotaSnapshotAge(snapshot *geminiQuotaSnapshot, now time.Time) time.Duration {
	if snapshot == nil || snapshot.CapturedAt.IsZero() {
		return 0
	}
	age := now.UTC().Sub(snapshot.CapturedAt.UTC())
	if age < 0 {
		return 0
	}
	return age
}

func isGeminiQuotaFresh(snapshot *geminiQuotaSnapshot, now time.Time, staleAfter time.Duration) bool {
	if snapshot == nil || snapshot.CapturedAt.IsZero() {
		return false
	}
	if staleAfter <= 0 {
		staleAfter = defaultGeminiQuotaStaleAfter
	}
	return geminiQuotaSnapshotAge(snapshot, now) <= staleAfter
}

type geminiQuotaRoutingDecision struct {
	preferGemini    bool
	snapshotPresent bool
	fresh           bool
	age             time.Duration
	snapshot        *geminiQuotaSnapshot
	availableTiers  []string
	exhaustedTiers  []string
	reason          string
}

func decideGeminiQuotaRouting(snapshot *geminiQuotaSnapshot, now time.Time, staleAfter time.Duration) geminiQuotaRoutingDecision {
	decision := geminiQuotaRoutingDecision{snapshot: snapshot}
	if snapshot == nil {
		decision.reason = "no cached gemini quota snapshot; assume limited"
		return decision
	}
	decision.snapshotPresent = true
	decision.age = geminiQuotaSnapshotAge(snapshot, now)
	if !isGeminiQuotaFresh(snapshot, now, staleAfter) {
		decision.reason = "cached gemini quota snapshot is stale; assume limited"
		return decision
	}
	decision.fresh = true
	if len(snapshot.Windows) == 0 {
		decision.reason = "fresh gemini quota snapshot has no tier windows; assume limited"
		return decision
	}
	for _, w := range snapshot.Windows {
		if isExhaustedWindow(w) {
			decision.exhaustedTiers = append(decision.exhaustedTiers, w.LimitID)
			continue
		}
		decision.availableTiers = append(decision.availableTiers, w.LimitID)
	}
	if len(decision.availableTiers) == 0 {
		decision.reason = "fresh gemini quota snapshot reports all tiers exhausted; assume limited"
		return decision
	}
	decision.preferGemini = true
	decision.reason = "fresh gemini quota snapshot has at least one tier with headroom"
	return decision
}

func (d geminiQuotaRoutingDecision) isGeminiTierAvailable(model string) bool {
	if !d.preferGemini {
		return false
	}
	limitID, ok := TierLimitIDForModel(model)
	if !ok {
		return false
	}
	for _, tier := range d.availableTiers {
		if tier == limitID {
			return true
		}
	}
	return false
}

func (s *geminiQuotaSnapshot) maxUsedPercent() float64 {
	if s == nil {
		return 0
	}
	max := 0.0
	for _, w := range s.Windows {
		if w.UsedPercent > max {
			max = w.UsedPercent
		}
	}
	return max
}

func isExhaustedWindow(w harnesses.QuotaWindow) bool {
	if strings.EqualFold(w.State, "exhausted") || strings.EqualFold(w.State, "blocked") {
		return true
	}
	return w.UsedPercent >= 95
}

package gemini

import (
	"encoding/json"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/safefs"
)

const geminiAuthFreshnessWindow = 7 * 24 * time.Hour

const (
	authTypeGeminiAPIKey = "gemini-api-key"
	authTypeOAuth        = "oauth-personal"
	authTypeVertexAI     = "vertex-ai"
	authTypeComputeADC   = "compute-default-credentials"
	authTypeGateway      = "gateway"
)

// authSnapshot captures non-secret Gemini CLI auth/account evidence. It never
// stores API keys, OAuth tokens, refresh tokens, or raw credential payloads.
type authSnapshot struct {
	Authenticated bool
	AuthType      string
	Account       *harnesses.AccountInfo
	CapturedAt    time.Time
	Fresh         bool
	Source        string
	Detail        string
}

// readAuthEvidence reads Gemini CLI auth evidence from the user's configured
// environment and ~/.gemini directory. It is best-effort because Gemini CLI has
// no stable non-interactive quota command; routing uses this as auth/account
// freshness evidence and exposes quota as unknown.
func readAuthEvidence(now time.Time) authSnapshot {
	if now.IsZero() {
		now = time.Now()
	}
	if authType := authTypeFromEnv(); authType != "" {
		return authSnapshot{
			Authenticated: true,
			AuthType:      authType,
			Account:       accountForAuthType(authType),
			CapturedAt:    now.UTC(),
			Fresh:         true,
			Source:        "environment",
			Detail:        "Gemini auth selected from environment; secret values are not read",
		}
	}
	home, err := os.UserHomeDir()
	if err != nil || home == "" {
		return authSnapshot{Source: "~/.gemini", Detail: "home directory unavailable"}
	}
	return readAuthEvidenceFromDir(filepath.Join(home, ".gemini"), now)
}

// readAuthEvidenceFromDir reads non-secret Gemini CLI auth evidence from a
// caller-provided .gemini directory. Tests use this for credential-free replay.
func readAuthEvidenceFromDir(dir string, now time.Time) authSnapshot {
	if now.IsZero() {
		now = time.Now()
	}
	settingsPath := filepath.Join(dir, "settings.json")
	authType, settingsTime, settingsOK := readSelectedAuthType(settingsPath)
	if authType == "" {
		return authSnapshot{
			Source:     settingsPath,
			CapturedAt: settingsTime,
			Fresh:      settingsOK && isFresh(settingsTime, now),
			Detail:     "Gemini CLI auth method not configured",
		}
	}

	switch authType {
	case authTypeOAuth:
		return readOAuthEvidence(dir, authType, settingsTime, now)
	case authTypeGeminiAPIKey, authTypeVertexAI, authTypeGateway, authTypeComputeADC:
		return authSnapshot{
			Authenticated: true,
			AuthType:      authType,
			Account:       accountForAuthType(authType),
			CapturedAt:    settingsTime,
			Fresh:         isFresh(settingsTime, now),
			Source:        settingsPath,
			Detail:        "Gemini CLI auth method configured; secret material is external to DDx",
		}
	default:
		return authSnapshot{
			AuthType:   authType,
			Source:     settingsPath,
			CapturedAt: settingsTime,
			Fresh:      isFresh(settingsTime, now),
			Detail:     "Gemini CLI auth method is not recognized by DDx",
		}
	}
}

func readSelectedAuthType(path string) (string, time.Time, bool) {
	st, err := os.Stat(path)
	if err != nil || st.IsDir() {
		return "", time.Time{}, false
	}
	data, err := safefs.ReadFile(path)
	if err != nil {
		return "", st.ModTime().UTC(), false
	}
	var settings struct {
		Security struct {
			Auth struct {
				SelectedType string `json:"selectedType"`
			} `json:"auth"`
		} `json:"security"`
	}
	if err := json.Unmarshal(data, &settings); err != nil {
		return "", st.ModTime().UTC(), false
	}
	return strings.TrimSpace(settings.Security.Auth.SelectedType), st.ModTime().UTC(), true
}

func readOAuthEvidence(dir, authType string, settingsTime, now time.Time) authSnapshot {
	oauthPath := filepath.Join(dir, "oauth_creds.json")
	st, err := os.Stat(oauthPath)
	if err != nil || st.IsDir() {
		return authSnapshot{
			AuthType:   authType,
			Source:     oauthPath,
			CapturedAt: settingsTime,
			Fresh:      isFresh(settingsTime, now),
			Detail:     "Gemini OAuth credentials are missing",
		}
	}
	data, err := safefs.ReadFile(oauthPath)
	if err != nil {
		return authSnapshot{
			AuthType:   authType,
			Source:     oauthPath,
			CapturedAt: st.ModTime().UTC(),
			Fresh:      isFresh(st.ModTime(), now),
			Detail:     "Gemini OAuth credentials could not be read",
		}
	}
	var creds struct {
		AccessToken  string `json:"access_token"`
		RefreshToken string `json:"refresh_token"`
		ExpiryDate   int64  `json:"expiry_date"`
	}
	if err := json.Unmarshal(data, &creds); err != nil {
		return authSnapshot{
			AuthType:   authType,
			Source:     oauthPath,
			CapturedAt: st.ModTime().UTC(),
			Fresh:      isFresh(st.ModTime(), now),
			Detail:     "Gemini OAuth credentials are malformed",
		}
	}
	authenticated := creds.RefreshToken != "" || creds.AccessToken != ""
	if creds.ExpiryDate > 0 && creds.RefreshToken == "" {
		expires := time.UnixMilli(creds.ExpiryDate)
		authenticated = authenticated && expires.After(now)
	}
	capturedAt := maxTime(settingsTime, st.ModTime().UTC())
	return authSnapshot{
		Authenticated: authenticated,
		AuthType:      authType,
		Account:       readGoogleAccount(dir),
		CapturedAt:    capturedAt,
		Fresh:         isFresh(capturedAt, now),
		Source:        oauthPath,
		Detail:        oauthDetail(authenticated),
	}
}

func readGoogleAccount(dir string) *harnesses.AccountInfo {
	data, err := safefs.ReadFile(filepath.Join(dir, "google_accounts.json"))
	if err != nil {
		return &harnesses.AccountInfo{PlanType: "Gemini OAuth"}
	}
	var accounts struct {
		Active string `json:"active"`
	}
	if err := json.Unmarshal(data, &accounts); err != nil {
		return &harnesses.AccountInfo{PlanType: "Gemini OAuth"}
	}
	account := &harnesses.AccountInfo{PlanType: "Gemini OAuth"}
	if strings.Contains(accounts.Active, "@") {
		account.Email = accounts.Active
	}
	return account
}

func accountForAuthType(authType string) *harnesses.AccountInfo {
	switch authType {
	case authTypeGeminiAPIKey:
		return &harnesses.AccountInfo{PlanType: "Gemini API key"}
	case authTypeVertexAI:
		return &harnesses.AccountInfo{PlanType: "Vertex AI"}
	case authTypeComputeADC:
		return &harnesses.AccountInfo{PlanType: "Google ADC"}
	case authTypeGateway:
		return &harnesses.AccountInfo{PlanType: "Gemini gateway"}
	default:
		return &harnesses.AccountInfo{PlanType: authType}
	}
}

func authTypeFromEnv() string {
	if os.Getenv("GOOGLE_GENAI_USE_GCA") != "" {
		return authTypeGateway
	}
	if os.Getenv("GOOGLE_GENAI_USE_VERTEXAI") != "" {
		return authTypeVertexAI
	}
	if os.Getenv("GOOGLE_API_KEY") != "" || os.Getenv("GEMINI_API_KEY") != "" {
		return authTypeGeminiAPIKey
	}
	if os.Getenv("CLOUD_SHELL") == "true" || os.Getenv("GEMINI_CLI_USE_COMPUTE_ADC") == "true" {
		return authTypeComputeADC
	}
	return ""
}

func oauthDetail(authenticated bool) string {
	if authenticated {
		return "Gemini OAuth credentials found; token values are not retained"
	}
	return "Gemini OAuth credentials do not contain usable token metadata"
}

func isFresh(capturedAt, now time.Time) bool {
	if capturedAt.IsZero() {
		return false
	}
	return now.Sub(capturedAt) <= geminiAuthFreshnessWindow
}

func maxTime(a, b time.Time) time.Time {
	if a.After(b) {
		return a
	}
	return b
}

